1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; cursed?: boolean; enchantment?: number };
13	type Step = { items: Item[] };
14	type Scenario = { steps: Step[] };
15	
16	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
17	const BLOCK_BASE_PREMIUM = 60;
18	
19	export function processScenario(scenario: unknown): unknown {
20	  const { steps } = scenario as Scenario;
21	  const items = steps[0].items;
22	  const componentCountsByType = new Map<string, number>();
23	  let basePremium = 0;
24	  for (const item of items) {
25	    if (COMPONENT_TYPES.has(item.type)) {
26	      componentCountsByType.set(
27	        item.type,
28	        (componentCountsByType.get(item.type) ?? 0) + 1,
29	      );
30	    } else {
31	      let itemPremium = BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
32	      if (item.cursed) {
33	        itemPremium += itemPremium * 0.5;
34	      }
35	      if (item.enchantment !== undefined && item.enchantment >= 5) {
36	        itemPremium += BASE_PREMIUM_BY_ITEM_TYPE[item.type] * 0.3;
37	      }
38	      basePremium += itemPremium;
39	    }
40	  }
41	  for (const [type, count] of componentCountsByType) {
42	    if (count === 3) {
43	      basePremium += BLOCK_BASE_PREMIUM;
44	    } else {
45	      basePremium += count * (BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0);
46	    }
47	  }
48	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
49	}
